const r=await this.helpers.httpRequest({method:'GET',url:'https://api.nevobo.nl/relatiebeheer/verenigingen?page=1',headers:{'Accept':'application/ld+json'},json:true});
const total=r['hydra:totalItems']||0; const per=((r['hydra:member']||[]).length)||30; const pages=Math.max(1,Math.ceil(total/per));
const fedId=(($('Webhook').first().json.body)||{}).id;
const out=[]; for(let p=1;p<=pages;p++) out.push({json:{page:p,fedId}});
return out;

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const fedId=$json.fedId; const page=$json.page;
const uslug=(s)=>String(s||'').toLowerCase().normalize('NFKC').replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'').slice(0,60);
const normUrl=(u)=>{u=String(u||'').trim().replace(/^https?:\/\//i,'');if(!u)return '';if(/[\s,]/.test(u)||!u.includes('.'))return '';return 'https://'+u;};
const isEmail=(e)=>/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e);
const now=new Date().toISOString();
const findClub=async(k)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:"(dedup_key='"+k+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
const findContact=async(e)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:"(email='"+e.replace(/'/g,'')+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
const r=await this.helpers.httpRequest({method:'GET',url:'https://api.nevobo.nl/relatiebeheer/verenigingen?page='+page,headers:{'Accept':'application/ld+json'},json:true});
const mem=r['hydra:member']||[]; let created=0,contactsC=0;
for(const m of mem){ const name=String(m.naam||m.officielenaam||'').trim(); if(!name) continue;
  const code=String(m.organisatiecode||'').toLowerCase(); const dedup='NED:'+(code||uslug(name));
  const website=normUrl(m.website);
  const base={federation:fedId,name,country:'Netherlands',region:String(m.provincie||''),city:String(m.vestigingsplaats||''),dedup_key:dedup,source_url:'https://api.nevobo.nl/relatiebeheer/verenigingen',source_club_id:String(m.organisatiecode||''),last_scraped:now};
  let clubId=null;
  try{ try{const rec=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:Object.assign({},base,{website_url:website,website_source:website?'official_list':'none',status:'new'}),json:true});created++;clubId=rec.id;}
    catch(e){const ex=await findClub(dedup); if(ex){const p=Object.assign({},base);if(website){p.website_url=website;p.website_source='official_list';}await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+ex.id,headers:pbH,body:p,json:true});clubId=ex.id;}else throw e;} }
  catch(e){continue;}
  const email=String(m.email||'').trim().toLowerCase();
  if(email&&isEmail(email)){ try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{club:clubId,email,phone:String(m.telefoon||''),source_url:'https://api.nevobo.nl/relatiebeheer/verenigingen',source_type:'directory',verification_status:'unverified'},json:true});contactsC++;}
    catch(e){try{const ex=await findContact(email);if(ex&&!ex.club)await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+ex.id,headers:pbH,body:{club:clubId,phone:String(m.telefoon||'')},json:true});}catch(_){}}
  }
}
return [{json:{page,members:mem.length,created,contactsC}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const fedId=(($('Webhook').first().json.body)||{}).id;
const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'federation="'+fedId+'"',perPage:1},headers:pbH,json:true});
const n=r.totalItems||0;
await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/federations/records/'+fedId,headers:pbH,body:{status:(n>0?'scraped':'needs_review'),club_count:n,last_scraped:new Date().toISOString(),scrape_note:'nevobo api: '+n+' clubs'},json:true});
return [{json:{ok:true,clubs:n}}];
